var novos = topics.filter(function(t) {
  var k = (t.milagre_de_jesus || '').toLowerCase().replace(/[^a-z ]/g, '').trim();
  return !usedSet[k];
});

if (novos.length === 0) throw new Error('All topics already used. Will generate new ones next run.');

novos.forEach(function(t) { store.usedTopics.push(t.milagre_de_jesus); });
if (store.usedTopics.length > 500) store.usedTopics = store.usedTopics.slice(-500);

var runId = cfg.RUN_ID || new Date().toISOString().replace(/[^0-9]/g, '').substring(0, 14);

// Incluir TODAS as credenciais em cada item de saida
return novos.map(function(topic, i) {
  return {
    json: {
      milagre_de_jesus: topic.milagre_de_jesus,
      versiculo_base: topic.versiculo_base,
      gancho_inicial: topic.gancho_inicial,
      palavras_chave: topic.palavras_chave,
      categoria: topic.categoria,
      runId: runId,
      topicIndex: i + 1,
      videoId: runId + '_video_' + String(i + 1).padStart(2, '0'),
      GOOGLE_AI_API_KEY: cfg.GOOGLE_AI_API_KEY || '',
      ELEVENLABS_API_KEY: cfg.ELEVENLABS_API_KEY || ''
    }
  };
});
